package arch.day28;

/**
 * Day 28 basic: println-only reference for fresher through staff readers.
 */
public class Day28Basic {

    public static void main(String[] args) {
        // Core idea: javac proves List<String>; JVM still loads erased List descriptors.
        System.out.println("=== Core concept table ===");
        System.out.println("scope    | this file is println-only — no collections or loops");
        System.out.println("List<String> compile | javac rejects list.add(Integer.valueOf(1))");
        System.out.println("List.add bytecode   | descriptor still takes java.lang.Object");
        System.out.println("getClass runtime    | same ArrayList class for String and Integer lists");
        System.out.println("covariant return    | triggers ACC_BRIDGE synthetic methods");
        System.out.println();

        // How to use the idea in week one: commands and flags you can copy from docs.
        System.out.println("=== How to use it (commands and flags) ===");
        System.out.println("javap -p Service.class       list ACC_BRIDGE synthetic methods");
        System.out.println("javap -c Service.class       inspect checkcast after erased calls");
        System.out.println("javac -Xlint:unchecked       surface unchecked warnings in modules");
        System.out.println("jcmd <pid> Thread.print      frame context around ClassCastException");
        System.out.println("java -version                confirm JDK family for bridge expectations");
        System.out.println();

        // Errors beginners blame on data but seniors tie to erased boundaries.
        System.out.println("=== Common beginner mistakes (symptoms) ===");
        System.out.println("ClassCastException        heap saw Long where String was promised");
        System.out.println("ArrayStoreException       varargs generic array took wrong runtime type");
        System.out.println("ClassCastException gson   LinkedTreeMap cast to Row without TypeToken");
        System.out.println("AbstractMethodError shade bridge pair missing after jar relocation");
        System.out.println();

        // Remember-this block before interview or on-call.
        System.out.println("=== Remember this ===");
        System.out.println("PECS     | producer extends | consumer super");
        System.out.println("Raw List | strips compile proofs | ban in new public APIs");
        System.out.println("Erasure  | Class<T> or TypeToken carries lost nested shapes");
        System.out.println("staff cue| grep 'List ' without angle brackets before blaming Jackson");
        System.out.println("staff cue| diff javap -p after MapStruct upgrades");
        System.out.println("staff cue| require TypeReference for nested JSON in code review");
        System.out.println("eof");
    }
}

package arch.day28;

/**
 * Day 28 intermediate: four on-call style generics narratives (println only).
 * Real prod teams blame Jackson or Gradle when JDBC raw Lists or wildcards are the real fault.
 * MapStruct bumps rename synthetic bridges—always diff javap before rollback.
 *
 * Mid-level readers should rehearse each scenario as a ticket narrative:
 * capture the command that proved root cause, paste javap snippets, and link the PR.
 * Generics incidents rarely throw during unit tests—they appear under mixed tenant data.
 * Keep scenario titles aligned with log lines your lead will search in Splunk or ELK.
 *
 * When you escalate, attach JVM version (java -version) because bridge behavior is stable
 * across LTS lines but warning text differs between javac releases and IDE inspectors.
 *
 * Remember: flipped PECS is cheaper to fix at compile time than rewriting APIs later.
 */
public class Day28Intermediate {

    // Scenario 1 hook: raw JDBC Lists are the silent author of Jackson ClassCastException stacks.
    static void scenario1() {
        System.out.println("--- Scenario 1: DTO hydration blows up after raw JDBC List ---");
        System.out.println("symptom:  HTTP 500 only for tenants with mixed numeric SKU identifiers");
        System.out.println("cause:    DAO returned raw List and caller treated it as List<String>");
        System.out.println("why:      erasure skipped checkcasts until Jackson readValue enforced String");
        System.out.println("fix:      JdbcTemplate.query with RowMapper<List<String>> or parser at JDBC edge");
        System.out.println("verify:   jcmd <pid> Thread.print shows checkcast to java.lang.String after Object");
        System.out.println("next:     grep raw List in DAO package; attach RowMapper diff to ticket");
        System.out.println();
    }

    // Scenario 2 hook: diff javap before rolling back a MapStruct upgrade.
    static void scenario2() {
        System.out.println("--- Scenario 2: Lombok bump lit up Repository$$Bridge in profiler ---");
        System.out.println("symptom:  jstack shows CovariantClient$$Bridge during MapStruct-heavy requests");
        System.out.println("cause:    narrowed generic return forced javac to synthesize ACC_BRIDGE methods");
        System.out.println("why:      JVM calls erased signature then bridges cast to specialized return type");
        System.out.println("fix:      keep upgrade when javap diff only adds expected synthetic bridges");
        System.out.println("verify:   javap -p ClientImpl.class and scan method flags for ACC_BRIDGE");
        System.out.println("next:     jcmd <pid> JFR.start duration=300s if CPU regression must be quantified");
        System.out.println();
    }

    // Scenario 3 hook: nested JSON always needs a TypeToken or JavaType witness.
    static void scenario3() {
        System.out.println("--- Scenario 3: Gson drops nested List<Row> inside ApiEnvelope JSON ---");
        System.out.println("symptom:  ClassCastException: LinkedTreeMap cannot be cast to Row in IT suite");
        System.out.println("cause:    gson.fromJson(payload, ApiEnvelope.class) erases nested List<Row>");
        System.out.println("why:      Class literal cannot carry ParameterizedType for inner generics");
        System.out.println("fix:      new TypeToken<ApiEnvelope<List<Row>>>(){}.getType() for HTTP client read");
        System.out.println("verify:   javap -v EnvelopeParser$1.class shows Signature attribute intact");
        System.out.println("next:     add CI rule blocking Class literal for nested generic JSON reads");
        System.out.println();
    }

    // Scenario 4 hook: flipped PECS belongs in API review, not midnight paging.
    static void scenario4() {
        System.out.println("--- Scenario 4: ingest API used List<? super Number> for a read-only aggregator ---");
        System.out.println("symptom:  Gradle compileJava fails when clients pass List<Integer> to mergeTotals");
        System.out.println("cause:    ? super Number marks a consumer sink but method never called add");
        System.out.println("why:      capture of ? cannot prove List<Integer> is valid argument type");
        System.out.println("fix:      read-only parameters should be List<? extends Number> per PECS");
        System.out.println("verify:   ./gradlew compileJava --info and confirm capture#1 error disappeared");
        System.out.println("next:     publish PECS one-pager next to every public Collection parameter");
        System.out.println();
    }

    public static void main(String[] args) {
        System.out.println("banner: Day28 intermediate arch.day28");
        System.out.println();
        scenario1();
        scenario2();
        scenario3();
        scenario4();
    }
}

package arch.day28;

import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

/**
 * Day 28 advanced: wildcard posture + erasure flags + checklist.
 */
public class Day28Advanced {

    record ApiPosture(String surface, String wildcardRule, int safetyScore) {}

    static List<ApiPosture> postureRows() {
        List<ApiPosture> rows = new ArrayList<>();
        rows.add(new ApiPosture("read-only return", "extends producer", 2));
        rows.add(new ApiPosture("sink parameter", "super consumer", 2));
        rows.add(new ApiPosture("internal algorithm", "named type param", 3));
        rows.add(new ApiPosture("JSON edge", "TypeToken or JavaType", 1));
        return rows;
    }

    static Map<String, Boolean> erasureFlags() {
        Map<String, Boolean> m = new LinkedHashMap<>();
        m.put("runtime instanceof List<String>", false);
        m.put("need Class<T> for reflection newInstance", true);
        m.put("bridges appear on covariant returns", true);
        m.put("raw types strip compiler proofs", true);
        return m;
    }

    public static void main(String[] args) {
        System.out.println("banner: Day28 advanced generics guardrails");
        System.out.println("scope: arch.day28 erasure + boundary matrix");
        System.out.println();
        System.out.println();

        System.out.println("=== Block 1: API posture table ===");
        for (ApiPosture r : postureRows()) {
            System.out.println(r.surface() + " | " + r.wildcardRule() + " | score=" + r.safetyScore());
        }
        System.out.println();

        System.out.println("=== Block 2: erasure truth board ===");
        int trueCount = 0;
        for (Map.Entry<String, Boolean> e : erasureFlags().entrySet()) {
            if (Boolean.TRUE.equals(e.getValue())) {
                trueCount++;
            }
            System.out.println(e.getKey() + " -> " + e.getValue());
        }
        System.out.println("trueStatements=" + trueCount);
        System.out.println();

        System.out.println("=== Block 3: merge checklist ===");
        Map<String, Boolean> checks = new LinkedHashMap<>();
        checks.put("shared modules compile with -Xlint:unchecked", false);
        checks.put("public APIs avoid raw types in signatures", true);
        checks.put("covariant services have javap bridge notes in PR", true);
        int pass = 0;
        for (Map.Entry<String, Boolean> c : checks.entrySet()) {
            if (Boolean.TRUE.equals(c.getValue())) {
                pass++;
            }
            System.out.println(c.getKey() + " | " + c.getValue());
        }
        System.out.println("pass count = " + pass + " / " + checks.size());
        System.out.println("eof");
    }
}

